"""requests: HTTP library — no cryptography primitives."""
import os
import urllib.parse


def get(url, params=None, timeout=30):
    parsed = urllib.parse.urlparse(url)
    if parsed.scheme not in ("http", "https"):
        raise ValueError(f"unsupported scheme: {parsed.scheme}")
    return {"url": url, "params": params, "timeout": timeout}


def post(url, data=None, json=None, timeout=30):
    return {"url": url, "data": data, "json": json, "timeout": timeout}
